// WalletRepository.kt
package com.example.payments.wallet

import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import java.util.UUID

class WalletRepository {

    private val _balanceCents = MutableStateFlow(0L)
    val balance: Flow<Long> = _balanceCents

    private val _transactions = MutableStateFlow<List<WalletTransaction>>(emptyList())
    val transactions: Flow<List<WalletTransaction>> = _transactions

    private val mutex = Mutex()

    suspend fun credit(amountCents: Long, description: String) = mutex.withLock {
        _balanceCents.value += amountCents
        recordTransaction(amountCents, description)
    }

    suspend fun debit(amountCents: Long, description: String): Boolean = mutex.withLock {
        return if (_balanceCents.value >= amountCents) {
            _balanceCents.value -= amountCents
            recordTransaction(-amountCents, description)
            true
        } else {
            false
        }
    }

    private fun recordTransaction(amountCents: Long, description: String) {
        val txn = WalletTransaction(
            id = UUID.randomUUID().toString(),
            amountCents = amountCents,
            timestamp = System.currentTimeMillis(),
            description = description
        )
        _transactions.value = _transactions.value + txn
    }
}



