package com.example.payments.billing

import android.app.Activity
import android.content.Context
import com.android.billingclient.api.*
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch

class BillingManager(
    private val context: Context,
    private val scope: CoroutineScope
) : PurchasesUpdatedListener, BillingClientStateListener {

    private val client: BillingClient = BillingClient.newBuilder(context)
        .setListener(this)
        .enablePendingPurchases()
        .build()

    private val _purchaseResults = MutableSharedFlow<com.example.payments.model.PaymentResult>()
    val purchaseResults: SharedFlow<com.example.payments.model.PaymentResult> = _purchaseResults.asSharedFlow()

    fun startConnection() {
        if (!client.isReady) client.startConnection(this)
    }

    fun endConnection() = client.endConnection()

    override fun onBillingSetupFinished(billingResult: BillingResult) {
        // Additional setup if required
    }

    override fun onBillingServiceDisconnected() {
        startConnection()
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    scope.launch {
                        _purchaseResults.emit(
                            com.example.payments.model.PaymentResult.Success(purchase.purchaseToken)
                        )
                    }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                scope.launch { _purchaseResults.emit(com.example.payments.model.PaymentResult.Canceled) }
            }
            else -> {
                scope.launch {
                    _purchaseResults.emit(
                        com.example.payments.model.PaymentResult.Failure(
                            billingResult.responseCode,
                            billingResult.debugMessage
                        )
                    )
                }
            }
        }
    }

    fun launchPurchaseFlow(activity: Activity, productId: String, @BillingClient.ProductType productType: String) {
        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(
                listOf(
                    QueryProductDetailsParams.Product.newBuilder()
                        .setProductId(productId)
                        .setProductType(productType)
                        .build()
                )
            ).build()

        client.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && productDetailsList.isNotEmpty()) {
                val productDetails = productDetailsList.first()
                val flowParams = BillingFlowParams.newBuilder()
                    .setProductDetailsParamsList(
                        listOf(
                            BillingFlowParams.ProductDetailsParams.newBuilder()
                                .setProductDetails(productDetails)
                                .build()
                        )
                    )
                    .build()
                client.launchBillingFlow(activity, flowParams)
            } else {
                scope.launch {
                    _purchaseResults.emit(
                        com.example.payments.model.PaymentResult.Failure(
                            billingResult.responseCode,
                            billingResult.debugMessage
                        )
                    )
                }
            }
        }
    }

    fun acknowledgePurchaseIfNeeded(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
            val params = AcknowledgePurchaseParams.newBuilder()
                .setPurchaseToken(purchase.purchaseToken)
                .build()
            client.acknowledgePurchase(params) { /* handle result if needed */ }
        }
    }

    fun consumePurchase(purchaseToken: String, onConsumed: (BillingResult) -> Unit) {
        val params = ConsumeParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()
        client.consumeAsync(params, onConsumed)
    }
}



