package com.example.payments

import android.app.Activity
import android.content.Context
import com.example.payments.billing.BillingManager
import com.example.payments.model.PaymentResult
import com.example.payments.security.SecureStorage
import com.example.payments.wallet.WalletRepository
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch

class PaymentManager private constructor(context: Context) {

    private val appScope = CoroutineScope(Dispatchers.IO)
    private val billingManager = BillingManager(context, appScope)
    private val walletRepository = WalletRepository()
    private val secureStorage = SecureStorage.get(context)

    val walletBalance: Flow<Long> = walletRepository.balance
    val purchaseResults: SharedFlow<PaymentResult> = billingManager.purchaseResults

    init {
        billingManager.startConnection()
        observePurchases()
    }

    fun launchInAppPurchase(activity: Activity, productId: String) {
        billingManager.launchPurchaseFlow(activity, productId, com.android.billingclient.api.BillingClient.ProductType.INAPP)
    }

    fun topUpWallet(cents: Long, description: String) {
        appScope.launch { walletRepository.credit(cents, description) }
    }

    fun spendFromWallet(cents: Long, description: String, onResult: (Boolean) -> Unit) {
        appScope.launch { onResult(walletRepository.debit(cents, description)) }
    }

    private fun observePurchases() {
        appScope.launch {
            purchaseResults.collect { result ->
                if (result is PaymentResult.Success) {
                    secureStorage.putString("last_purchase_token", result.purchaseToken)
                    // Post-launch security hardening placeholder
                }
            }
        }
    }

    fun shutdown() {
        billingManager.endConnection()
    }

    companion object {
        @Volatile
        private var INSTANCE: PaymentManager? = null

        fun get(context: Context): PaymentManager =
            INSTANCE ?: synchronized(this) {
                INSTANCE ?: PaymentManager(context.applicationContext).also { INSTANCE = it }
            }
    }
}